boot.artifact:
// inferred-not-tested:包根 @2/+esm 实测无法打包,改用包内真实 ESM 文件;其 CSS 会注入 document.head
const { default: EditorJS } = await import('https://cdn.jsdelivr.net/npm/@editorjs/editorjs@2/dist/editorjs.mjs');
const holder = document.getElementById('editor');
const doc = { blocks: data.blocks, ...(data.time == null ? {} : { time: data.time }), ...(data.version ? { version: data.version } : {}) };
const editor = new EditorJS({ holder, data: doc, readOnly: data.readOnly ?? false });
await editor.isReady;

boot.widget:
// Editor.js 会向 head 注入 CSS:动态 import 前后做差,把新增 style 搬入 widget shadow(铁律 2)
const before = new Set(document.head.querySelectorAll('style'));
const { default: EditorJS } = await import('https://cdn.jsdelivr.net/npm/@editorjs/editorjs@2/dist/editorjs.mjs');
for (const s of document.head.querySelectorAll('style')) if (!before.has(s)) { shadowRoot.appendChild(s.cloneNode(true)); s.remove(); }
const holder = shadowRoot.appendChild(document.createElement('div'));
const editor = new EditorJS({ holder, data: { blocks: data.blocks }, readOnly: data.readOnly ?? false }); await editor.isReady;
